# leaving "pending" forever.

_storage: SpecialistStorage | None = None


def get_specialist_storage() -> SpecialistStorage:
    """Lazy per-module storage (respects MYCELIUM_AGENT_DATA_DIR for tests)."""
    global _storage
    if _storage is None:
        _storage = SpecialistStorage(category="relationships")
    return _storage


def _coerce(state: MyceliumGraphState | dict[str, Any]) -> MyceliumGraphState:
    if isinstance(state, MyceliumGraphState):
        return state
    return MyceliumGraphState.model_validate(state)


def _resolve_invocation_ids(state: MyceliumGraphState) -> tuple[str | None, str | None]:
    return state.invocation_thread_id, state.invocation_trace_id


def _resolve_id(state: MyceliumGraphState) -> str | None:
    if state.current_id:
        return state.current_id
    ctx = state.context if isinstance(state.context, dict) else {}
    seed = ctx.get("seed")
    if isinstance(seed, dict):
        return seed.get("id")
    if isinstance(seed, list) and len(seed) == 1 and isinstance(seed[0], dict):
        return seed[0].get("id")
    if state.matched_persons and len(state.matched_persons) == 1:
        return state.matched_persons[0].get("id")
    return None


def _resolve_owned_fields(state: MyceliumGraphState) -> list[str]:
    if state.target_fields:
        return list(state.target_fields)
    owned: list[str] = []
    for cl in state.classifications or []:
        if cl.get("category") == "relationships" and cl.get("attribute"):
            owned.append(cl["attribute"])
    if owned:
        return owned
    return [
        a.strip().lower()
        for a in state.query.requested_attributes
        if a.strip()
    ] or ["relationships data"]


def _identity_from_context(ctx: dict[str, Any]) -> list[dict[str, Any]]:
    seed = ctx.get("seed")
    if isinstance(seed, dict):
        rows = [seed]
    elif isinstance(seed, list):
        rows = [r for r in seed if isinstance(r, dict)]
    else:
        rows = []
    records: list[dict[str, Any]] = []
    for rec in rows:
        pid = rec.get("id", "")
        records.append(
            {
                "id": pid,
                "name": rec.get("name", ""),
                "employer": rec.get("employer"),
            },
        )
    return records


def _field_has_value(entry: Any) -> bool:
    if entry is None:
        return False
    if isinstance(entry, dict):
        status = entry.get("status")
        if status in ("pending", "na"):
            return False
        return "value" in entry or status == "found"
    return True


def _field_is_pending(entry: Any) -> bool:
    return isinstance(entry, dict) and entry.get("status") == "pending"


def _field_is_na(entry: Any) -> bool:
    return isinstance(entry, dict) and entry.get("status") == "na"


def _field_display_value(entry: Any) -> str:
    if isinstance(entry, dict):
        if entry.get("status") == "na":
            return "N/A"
        return str(entry.get("value", entry.get("status", "")))
    return str(entry)


def _stub_background_research(
    pid: str,
    owned_fields: list[str],
    ctx: dict[str, Any],
    storage: SpecialistStorage,
) -> None:
    """Stub research thread (LLM+tools + persist results deferred to a later phase)."""
    _ = ctx, owned_fields
    # Placeholder: real implementation will use context (seed + other specialists) here.


def _start_research_if_needed(
    pid: str,
    field: str,
    owned_fields: list[str],
    ctx: dict[str, Any],
    storage: SpecialistStorage,
) -> None:
    data = storage.load()
    records = data.setdefault("records", {})
    rec = records.setdefault(pid, {})
    if _field_is_pending(rec.get(field)) or _field_has_value(rec.get(field)):
        return
    rec[field] = {
        "status": "pending",
        "started_at": datetime.now(timezone.utc).isoformat(),
    }
    storage.save(data)
    thread = threading.Thread(
        target=_stub_background_research,
        args=(pid, owned_fields, ctx, storage),
        daemon=True,
        name=f"relationships_specialist-research-{pid[:8]}",
    )
    thread.start()


def _evaluate_owned_fields(
    pid: str,
    owned: list[str],
    ctx: dict[str, Any],
    storage: SpecialistStorage,
) -> tuple[dict[str, Any], str, list[str]]:
    """
    Apply the 3 scenarios per owned field.

    Returns (values map, overall status, attrs still pending/unavailable).
    """
    data = storage.load()
    rec = data.get("records", {}).get(pid, {})
    values: dict[str, Any] = {}
    pending_attrs: list[str] = []
    na_attrs: list[str] = []
    found_attrs: list[str] = []

    for field in owned:
        entry = rec.get(field)
        if _field_has_value(entry):
            values[field] = _field_display_value(entry)
            found_attrs.append(field)
        elif _field_is_na(entry):
            values[field] = "N/A"
            na_attrs.append(field)
        elif _field_is_pending(entry):
            values[field] = "pending"
            pending_attrs.append(field)
        else:
            _start_research_if_needed(pid, field, owned, ctx, storage)
            values[field] = "pending"
            pending_attrs.append(field)

    if pending_attrs:
        overall = "pending"
    elif found_attrs and not na_attrs:
        overall = "found"
    elif na_attrs and not found_attrs and not pending_attrs:
        overall = "na"
    else:
        overall = "mixed"

    return values, overall, pending_attrs


def relationships_specialist(state: MyceliumGraphState | dict[str, Any]) -> dict[str, Any]:
    """
    Specialist for "relationships": context + id + owned fields only.

    Synchronous graph node; returns response + specialist_contrib for downstream assembly.
    """
    current = _coerce(state)
    ctx = current.context if isinstance(current.context, dict) else {}
    pid = _resolve_id(current)
    owned = _resolve_owned_fields(current)
    my_store = get_specialist_storage()
    thread_id, trace_id = _resolve_invocation_ids(current)
    id_kwargs = {"thread_id": thread_id, "trace_id": trace_id}
    clf_kwargs = (
        {"classifications": current.classifications}
        if current.classifications
        else {}
    )
    identity_records = _identity_from_context(ctx)

    if not pid:
        resp = response_not_found(current.query, specialist="relationships_specialist", **id_kwargs, **clf_kwargs)
        contrib = {"id": None, "fields": owned, "values": {}, "status": "not_found"}
        return {
            "response": resp,
            "route": None,
            "audit_log": [
                f"relationships_specialist: no id in state for {current.query.person_key!r}.",
            ],
            "specialist_contrib": contrib,
            "matched_persons": current.matched_persons or [],
            "classifications": current.classifications or [],
            **({"invocation_thread_id": thread_id} if thread_id else {}),
            **({"invocation_trace_id": trace_id} if trace_id else {}),
        }

    values, overall_status, pending_attrs = _evaluate_owned_fields(
        pid,
        owned,
        ctx,
        my_store,
    )

    contrib: dict[str, Any] = {
        "id": pid,
        "category": "relationships",
        "fields": owned,
        "values": values,
        "status": overall_status,
    }

    if overall_status == "found":
        message_extra = ", ".join(f"{k}: {v}" for k, v in values.items())
        resp = response_found(
            current.query,
            base_records=identity_records or None,
            specialist="relationships_specialist",
            **id_kwargs,
            **clf_kwargs,
        )
        if message_extra:
            resp = resp.model_copy(
                update={"message": f"{resp.message} {message_extra}."},
            )
        outcome = "found"
    elif overall_status == "na":
        na_list = ", ".join(owned)
        resp = response_non_core(
            current.query,
            base_records=identity_records or None,
            attributes=[f"{a} (N/A)" for a in owned],
            specialist="relationships_specialist",
            **id_kwargs,
            **clf_kwargs,
        )
        resp = resp.model_copy(
            update={
                "message": (
                    f"Found record for {identity_records[0]['name'] if identity_records else current.query.person_key}. "
                    f"{na_list} marked N/A (via relationships_specialist)."
                ),
            },
        )
        outcome = "na"
    else:
        attr_list = ", ".join(pending_attrs or owned)
        resp = response_non_core(
            current.query,
            base_records=identity_records or None,
            attributes=pending_attrs or owned,
            specialist="relationships_specialist",
            **id_kwargs,
            **clf_kwargs,
        )
        resp = resp.model_copy(
            update={
                "message": (
                    f"Found record for {identity_records[0]['name'] if identity_records else current.query.person_key}. "
                    f"{attr_list} not currently available but may be in the future "
                    f"(via relationships_specialist)."
                ),
            },
        )
        outcome = "pending"

    store_snapshot = my_store.load()
    record_count = len(store_snapshot.get("records", {}))
    logs = [
        f"relationships_specialist: {outcome} for id={pid!r} (category=relationships).",
        f"relationships_specialist: specialist store has {record_count} record(s).",
    ]

    payload: dict[str, Any] = {
        "response": resp,
        "route": None,
        "audit_log": logs,
        "specialist_contrib": contrib,
        "matched_persons": current.matched_persons or [],
        "classifications": current.classifications or [],
        "context": ctx,
        "current_id": pid,
        "target_fields": owned,
    }
    if identity_records and len(identity_records) == 1:
        from models.state import Person

        ir = identity_records[0]
        payload["person"] = Person(
            id=ir.get("id", ""),
            name=ir.get("name", ""),
            employer=ir.get("employer"),
        )
    if current.invocation_thread_id is not None:
        payload["invocation_thread_id"] = current.invocation_thread_id
    if current.invocation_trace_id is not None:
        payload["invocation_trace_id"] = current.invocation_trace_id
    return payload